def _get_or_prompt_flavor_id(runtime_client: RuntimeClient, console: Console) -> str:
    """Get flavor_id from config or prompt user to select from available flavors.
    
    Args:
        runtime_client: RuntimeClient instance for fetching flavors
        console: Console instance for displaying output
        
    Returns:
        Selected flavor_id string
        
    Raises:
        click.Abort: If flavor_id cannot be obtained
    """
    # Check if flavor_id exists in runtime config
    flavor_id = get_runtime_config_key("flavorId")
    if flavor_id:
        return flavor_id
    
    # Fetch available flavors and prompt user to select
    try:
        # Use run_async_with_cleanup to call async method from sync context
        flavors_response = run_async_with_cleanup(runtime_client, runtime_client.list_all_async())
        # Handle array response
        if isinstance(flavors_response, list):
            flavors = flavors_response
        elif hasattr(flavors_response, "listData"):
            flavors = flavors_response.listData or []
        else:
            flavors = []

        if not flavors:
            console.print("[yellow]Warning: No flavors available. You'll need to provide a flavorId.[/yellow]")
            flavor_id = Prompt.ask("Enter flavorId", default="")
            if not flavor_id:
                console.print("[red]Error: flavorId is required[/red]")
                raise click.Abort()
            return flavor_id
        else:
            # Display flavors
            flavor_lines = []
            for i, flavor in enumerate(flavors, 1):
                flavor_name = flavor.get("name") if isinstance(flavor, dict) else getattr(flavor, "name", "Unknown")
                flavor_cpu = flavor.get("cpu") if isinstance(flavor, dict) else getattr(flavor, "cpu", "N/A")
                flavor_ram = flavor.get("ram") if isinstance(flavor, dict) else getattr(flavor, "ram", "N/A")
                flavor_lines.append(f"  {i}. {flavor_name} (CPU: {flavor_cpu}, RAM: {flavor_ram}MB)")

            flavor_panel = Panel(
                "\n".join(flavor_lines),
                title="[bold blue]Available Flavors[/bold blue]",
                border_style="blue",
            )
            console.print("\n")
            console.print(flavor_panel)

            # Prompt user to select
            selected = Prompt.ask(
                f"\nSelect flavor (1-{len(flavors)})",
                default="1",
            )
            try:
                selected_idx = int(selected) - 1
                if 0 <= selected_idx < len(flavors):
                    selected_flavor = flavors[selected_idx]
                    flavor_id = selected_flavor.get("id") if isinstance(selected_flavor, dict) else getattr(selected_flavor, "id", None)
                    if flavor_id:
                        save_runtime_config_key("flavorId", flavor_id)
                        return flavor_id
                    else:
                        console.print("[red]Error: Selected flavor has no ID[/red]")
                        raise click.Abort()
                else:
                    console.print("[red]Error: Invalid selection[/red]")
                    raise click.Abort()
            except (ValueError, IndexError):
                console.print("[red]Error: Invalid selection[/red]")
                raise click.Abort()
    except Exception as flavor_error:
        logger.warning("Failed to fetch flavors: %s", flavor_error)
        console.print(f"[yellow]Warning: Failed to fetch flavors: {flavor_error}[/yellow]")
        flavor_id = Prompt.ask("Enter flavorId", default="")
        if not flavor_id:
            console.print("[red]Error: flavorId is required[/red]")
            raise click.Abort()
        return flavor_id


def _prompt_autoscaling(
    console: Console,
    runtime_defaults: Optional[AgentRuntimeAutoscaling] = None,
) -> AgentRuntimeAutoscaling:
    """Prompt user for autoscaling config with validation. Uses .greennode_runtime.json as default.

    Args:
        console: Console for output
        runtime_defaults: Optional defaults from current runtime (e.g. for deploy update)

    Validation:
        min_replicas: >= 1
        max_replicas: <= 10
        cpu_utilization: >= 25
        memory_utilization: <= 90

    Returns:
        AgentRuntimeAutoscaling with validated values. Saves to config for future runs.
    """
    defaults = runtime_defaults or AgentRuntimeAutoscaling()
    config = get_runtime_autoscaling_config()
    if config:
        try:
            defaults = AgentRuntimeAutoscaling(
                min_replicas=config.get("minReplicas") or config.get("min_replicas", defaults.min_replicas),
                max_replicas=config.get("maxReplicas") or config.get("max_replicas", defaults.max_replicas),
                cpu_utilization=config.get("cpuUtilization") or config.get("cpu_utilization", defaults.cpu_utilization),
                memory_utilization=config.get("memoryUtilization") or config.get("memory_utilization", defaults.memory_utilization),
            )
        except Exception:
            pass

    console.print("\n[bold blue]Auto-scaling configuration[/bold blue]")

    def _prompt_int(
        label: str,
        default: int,
        min_val: Optional[int] = None,
        max_val: Optional[int] = None,
    ) -> int:
        while True:
            raw = Prompt.ask(label, default=str(default))
            try:
                val = int(raw)
                if min_val is not None and val < min_val:
                    console.print(f"[red]Value must be >= {min_val}[/red]")
                    continue
                if max_val is not None and val > max_val:
                    console.print(f"[red]Value must be <= {max_val}[/red]")
                    continue
                return val
            except ValueError:
                console.print("[red]Please enter a valid integer[/red]")

    min_replicas = _prompt_int("min_replicas", defaults.min_replicas, min_val=1, max_val=10)
    max_replicas = _prompt_int("max_replicas", defaults.max_replicas, min_val=1, max_val=10)
    cpu_utilization = _prompt_int("cpu_utilization", defaults.cpu_utilization, min_val=25)
    memory_utilization = _prompt_int("memory_utilization", defaults.memory_utilization, min_val=25, max_val=90)

    autoscaling = AgentRuntimeAutoscaling(
        min_replicas=min_replicas,
        max_replicas=max_replicas,
        cpu_utilization=cpu_utilization,
        memory_utilization=memory_utilization,
    )
    save_runtime_config_key(
        "autoscaling",
        {
            "minReplicas": min_replicas,
            "maxReplicas": max_replicas,
            "cpuUtilization": cpu_utilization,
            "memoryUtilization": memory_utilization,
        },
    )
    return autoscaling


def _format_config_item(name: str, is_present: bool, required: bool = True, is_file: bool = False) -> str:
    """Format a configuration item for display.

    Args:
        name: Configuration item name
        is_present: Whether the configuration is present
        required: Whether the configuration is required
        is_file: Whether this is a file check (not an env var)

    Returns:
        Formatted string with checkmark and color coding using rich markup
    """
    if is_present:
        if required:
            checkmark = "[green]✓[/green]"
        else:
            checkmark = "[dim green]○[/dim green]"
    else:
        if required:
            checkmark = "[red]✗[/red]"
        else:
            checkmark = "[dim]○[/dim]"

    if not required:
        suffix = " [dim](optional)[/dim]"
    else:
        suffix = ""

    return f"{checkmark} {name}{suffix}"


def _check_and_display_deploy_config() -> tuple[bool, dict[str, bool]]:
    """Check and display deployment configuration status.

    Displays a checklist of deployment-specific configuration items using rich visualization.
    Returns whether all required conditions are met and a status dictionary.

    Returns:
        Tuple of (all_required_met: bool, status_dict: dict) where status_dict contains
        the presence status of each configuration item.
    """
    console = Console()

    # Check deployment configurations
    greennode_client_id = get_config_value("GREENNODE_CLIENT_ID")
    greennode_client_secret = get_config_value("GREENNODE_CLIENT_SECRET")
    registry_url = get_config_value("GREENNODE_REGISTRY_URL")
    registry_username = get_config_value("GREENNODE_REGISTRY_USERNAME")
    registry_password = get_config_value("GREENNODE_REGISTRY_PASSWORD")
    requirements_exists = Path("requirements.txt").exists()
    dockerfile_exists = Path("Dockerfile").exists()
    docker_running = is_docker_running()

    # Build deployment configuration panel content
    deploy_lines = []
    deploy_lines.append(_format_config_item("GREENNODE_CLIENT_ID", greennode_client_id is not None, required=True))
    deploy_lines.append(_format_config_item("GREENNODE_CLIENT_SECRET", greennode_client_secret is not None, required=True))
    deploy_lines.append(_format_config_item("GREENNODE_REGISTRY_URL", registry_url is not None, required=True))
    deploy_lines.append(_format_config_item("GREENNODE_REGISTRY_USERNAME", registry_username is not None, required=True))
    deploy_lines.append(_format_config_item("GREENNODE_REGISTRY_PASSWORD", registry_password is not None, required=True))
    deploy_lines.append(_format_config_item("requirements.txt", requirements_exists, required=True, is_file=True))
    deploy_lines.append(_format_config_item("Dockerfile", dockerfile_exists, required=True, is_file=True))
    deploy_lines.append(_format_config_item("Docker", docker_running, required=True))

    deploy_panel = Panel(
        "\n".join(deploy_lines),
        title="Deployment Configuration",
        border_style="yellow",
    )

    # Display deployment configuration panel
    console.print(deploy_panel)

    # Check if all required conditions are met
    all_required_met = (
        greennode_client_id is not None
        and greennode_client_secret is not None
        and registry_url is not None
        and registry_username is not None
        and registry_password is not None
        and requirements_exists
        and dockerfile_exists
        and docker_running
    )

    status_dict = {
        "GREENNODE_CLIENT_ID": greennode_client_id is not None,
        "GREENNODE_CLIENT_SECRET": greennode_client_secret is not None,
        "GREENNODE_REGISTRY_URL": registry_url is not None,
        "GREENNODE_REGISTRY_USERNAME": registry_username is not None,
        "GREENNODE_REGISTRY_PASSWORD": registry_password is not None,
        "requirements.txt": requirements_exists,
        "Dockerfile": dockerfile_exists,
        "Docker": docker_running,
    }

    return all_required_met, status_dict


def _secure_display_value(value: str) -> str:
    """Display a secure value showing only first 10 characters.

    Args:
        value: The value to display securely

    Returns:
        Secure display string with first 10 chars visible, rest as asterisks
    """
    if not value or len(value) <= 10:
        return "*" * len(value) if value else "(empty)"
    return value[:10] + "*" * (len(value) - 10)


def _format_docker_log_chunk(chunk: Dict[str, Any]) -> Optional[str]:
    """Format a Docker API log chunk into a displayable string.

    Args:
        chunk: Docker API log chunk dictionary

    Returns:
        Formatted log line string, or None if chunk should be skipped
    """
    if "stream" in chunk:
        line = chunk["stream"].strip()
        return line if line else None
    elif "status" in chunk:
        status = chunk["status"]
        if "progress" in chunk:
            progress = chunk["progress"]
            return f"{status} {progress}"
        return status
    elif "error" in chunk:
        return f"ERROR: {chunk['error']}"
    elif "errorDetail" in chunk:
        error_detail = chunk["errorDetail"]
        message = error_detail.get("message", "Unknown error")
        return f"ERROR: {message}"
    return None


def _build_and_push_image(
    full_image_name: str,
    registry_username: str,
    registry_password: str,
) -> None:
    """Build Docker image from current directory and push to registry.

    Uses streaming build/push logs with Live panel. Raises or aborts on failure.

    Args:
        full_image_name: Full image name including registry and tag (e.g. registry/name:tag).
        registry_username: Registry username for push.
        registry_password: Registry password for push.

    Raises:
        click.Abort: On missing Docker SDK, Docker daemon failure, or build/push failure.
        GreenNodeConfigurationError: If Dockerfile is missing.
        GreenNodeRuntimeError: If build completes but image not found.
    """
    try:
        import docker
    except ImportError:
        logger.error("Docker Python SDK (docker package) is not installed")
        console = Console()
        console.print("[red]Error: Docker Python SDK (docker package) is not installed[/red]")
        console.print("[yellow]Please install it with: pip install docker>=6.0.0[/yellow]")
        raise click.Abort()

    try:
        docker_client = docker.from_env()
    except Exception as e:
        logger.error("Failed to connect to Docker daemon: %s", e)
        Console().print(f"[red]Error: Failed to connect to Docker daemon: {e}[/red]")
        raise click.Abort()

    console_instance = Console()

    # Build Docker image
    logger.info("Building Docker image...")
    console_instance.print("\n[bold blue]Building Docker image...[/bold blue]")
    try:
        dockerfile_path = Path("Dockerfile")
        if not dockerfile_path.exists():
            raise GreenNodeConfigurationError(
                "Dockerfile not found in current directory. "
                "Please create a Dockerfile before deploying."
            )

        log_buffer = deque(maxlen=30)
        api_client = docker_client.api
        build_generator = api_client.build(
            path=".",
            tag=full_image_name,
            platform="linux/amd64",
            rm=True,
            decode=True,
        )

        panel = Panel("", title="[bold blue]Building Docker Image...[/bold blue]", border_style="blue")
        try:
            with Live(panel, console=console_instance, refresh_per_second=10) as live:
                try:
                    for chunk in build_generator:
                        log_line = _format_docker_log_chunk(chunk)
                        if log_line:
                            log_buffer.append(log_line)
                            panel_content = "\n".join(log_buffer) if log_buffer else "Starting build..."
                            live.update(
                                Panel(
                                    panel_content,
                                    title="[bold blue]Building Docker Image...[/bold blue]",
                                    border_style="blue",
                                )
                            )
                        if "error" in chunk or "errorDetail" in chunk:
                            error_msg = chunk.get("error") or chunk.get("errorDetail", {}).get("message", "Unknown error")
                            log_buffer.append(f"ERROR: {error_msg}")
                            live.update(
                                Panel(
                                    "\n".join(log_buffer),
                                    title="[bold red]Build Error[/bold red]",
                                    border_style="red",
                                )
                            )
                except Exception as stream_error:
                    error_msg = str(stream_error)
                    log_buffer.append(f"ERROR: {error_msg}")
                    live.update(
                        Panel(
                            "\n".join(log_buffer),
                            title="[bold red]Build Error[/bold red]",
                            border_style="red",
                        )
                    )
                    time.sleep(0.5)
                    raise
        finally:
            pass

        try:
            docker_client.images.get(full_image_name)
            logger.info("Docker image built successfully: %s", full_image_name)
            console_instance.print("[green]✓ Docker image built successfully[/green]")
        except Exception as img_error:
            raise GreenNodeRuntimeError(
                "Build completed but image not found",
                details={"image_name": full_image_name},
                cause=img_error,
            ) from img_error

    except GreenNodeConfigurationError:
        raise
    except GreenNodeRuntimeError:
        raise
    except Exception as e:
        logger.error("Failed to build Docker image: %s", e)
        console_instance.print(f"[red]Error: Failed to build Docker image: {e}[/red]")
        raise click.Abort()

    # Push image to registry
    logger.info("Pushing image to registry...")
    console_instance.print("\n[bold yellow]Pushing image to registry...[/bold yellow]")
    try:
        api_client = docker_client.api
        push_generator = api_client.push(
            full_image_name,
            auth_config={"username": registry_username, "password": registry_password},
            stream=True,
            decode=True,
        )

        log_buffer = deque(maxlen=30)
        panel = Panel("", title="[bold yellow]Pushing to Registry...[/bold yellow]", border_style="yellow")
        try:
            with Live(panel, console=console_instance, refresh_per_second=10) as live:
                try:
                    for chunk in push_generator:
                        log_line = _format_docker_log_chunk(chunk)
                        if log_line:
                            log_buffer.append(log_line)
                            panel_content = "\n".join(log_buffer) if log_buffer else "Starting push..."
                            live.update(
                                Panel(
                                    panel_content,
                                    title="[bold yellow]Pushing to Registry...[/bold yellow]",
                                    border_style="yellow",
                                )
                            )
                        if "error" in chunk or "errorDetail" in chunk:
                            error_msg = chunk.get("error") or chunk.get("errorDetail", {}).get("message", "Unknown error")
                            log_buffer.append(f"ERROR: {error_msg}")
                            live.update(
                                Panel(
                                    "\n".join(log_buffer),
                                    title="[bold red]Push Error[/bold red]",
                                    border_style="red",
                                )
                            )
                except Exception as stream_error:
                    error_msg = str(stream_error)
                    log_buffer.append(f"ERROR: {error_msg}")
                    live.update(
                        Panel(
                            "\n".join(log_buffer),
                            title="[bold red]Push Error[/bold red]",
                            border_style="red",
                        )
                    )
                    time.sleep(0.5)
                    raise
        finally:
            pass

        logger.info("Image pushed successfully to registry: %s", full_image_name)
        console_instance.print("[green]✓ Image pushed successfully to registry[/green]")

    except Exception as e:
        logger.error("Failed to push Docker image: %s", e)
        console_instance.print(f"[red]Error: Failed to push Docker image: {e}[/red]")
        raise click.Abort()


@click.group(name="deploy", context_settings=CONTEXT_SETTINGS)
def deploy_group() -> None:
    """Deploy your AI agent to GreenNode runtime platform.
    
    This command group provides deployment operations for AI agents built with
    GreenNode AgentBase SDK.
    """
    pass


@deploy_group.command(name="run")
@click.option(
    "--image-name",
    "-i",
    type=str,
    default=None,
    help="Custom image name. If not provided, defaults to agentbase-worker-{agent_identity}",
)
@click.option(
    "--output",
    "-o",
    type=click.Choice(["id"]),
    default=None,
    help="Output only the runtime id (for scripting). Use -o id to print just the id.",
)
def deploy_command(image_name: Optional[str], output: Optional[str]) -> None:
    """Deploy your AI agent to GreenNode runtime platform.

    This command builds a Docker image, pushes it to the registry, and creates
    a runtime instance on the GreenNode platform.

    The deployment process includes:
    1. Checking deployment configuration (registry, Docker, files)
    2. Collecting GREENNODE environment variables
    3. Building Docker image
    4. Pushing image to registry
    5. Creating runtime on GreenNode platform

    Examples:
        \n
        # Deploy with default image name\n
        greennode deploy run

        \n
        # Deploy with custom image name\n
        greennode deploy run --image-name my-custom-agent
    """
    console = Console()

    # Check if running in runtime environment
    if get_config_value("GREENNODE_RUNTIME"):
        logger.info("Running in runtime environment, deployment bypassed")
        console.print("[yellow]Running in runtime environment, deployment bypassed[/yellow]")
        return

    logger.info("Starting deployment process...")
    console.print("[bold blue]Starting deployment process...[/bold blue]\n")

    # Display deployment configuration checklist
    all_required_met, status_dict = _check_and_display_deploy_config()

    # Early validation - return if required conditions are not met
    if not all_required_met:
        logger.warning("Deployment aborted: required conditions not met")
        missing_items = [key for key, value in status_dict.items() if not value]
        logger.warning("Missing required items: %s", ", ".join(missing_items))
        console.print(f"\n[red]Deployment aborted: Missing required items: {', '.join(missing_items)}[/red]")
        if "Docker" in missing_items:
            docker_cmd = "docker context inspect --format '{{ .Endpoints.docker.Host }}'"
            console.print(f"\n[red]⚠ Docker daemon is not running or engine mismatch.[/red]")
            console.print(f"[yellow]Check your socket with:[/yellow] [bold cyan]{docker_cmd}[/bold cyan]")
            console.print(f"[yellow]Then set it with:[/yellow] [bold cyan]export DOCKER_HOST=\"result_here\"[/bold cyan]")
        raise click.Abort()

    # Check/create .greennode_runtime.json and collect GREENNODE env vars
    ensure_runtime_config_exists()

    # Validate that sensitive env vars are NOT in config file
    config_env_vars = get_runtime_env_vars()
    sensitive_vars = [
        "GREENNODE_CLIENT_ID",
        "GREENNODE_CLIENT_SECRET",
        "GREENNODE_AGENT_IDENTITY",
    ]
    found_sensitive_vars = [var for var in sensitive_vars if var in config_env_vars]
    
    if found_sensitive_vars:
        logger.error("Sensitive environment variables found in .greennode_runtime.json: %s", ", ".join(found_sensitive_vars))
        console.print(
            f"\n[red]Error: The following sensitive environment variables are present in .greennode_runtime.json:[/red]\n"
            f"[red]{', '.join(found_sensitive_vars)}[/red]\n"
            f"[yellow]These variables should not be stored in the config file for security reasons.[/yellow]\n"
            f"[yellow]Please remove them from .greennode_runtime.json and use environment variables instead.[/yellow]"
        )
        raise click.Abort()

    # Required GREENNODE environment variables
    required_greennode_vars = [
        "GREENNODE_CLIENT_ID",
        "GREENNODE_CLIENT_SECRET",
        "GREENNODE_AGENT_IDENTITY",
    ]

    # Collect env vars from environment, config file, or prompt user
    env_vars = {}
    missing_vars = []

    for var_name in required_greennode_vars:
        # Get from env first, then .greennode.json
        value = get_config_value(var_name)
        if not value:
            missing_vars.append(var_name)
        else:
            env_vars[var_name] = value

    # Display current env vars with secure values
    env_lines = []
    for var_name in required_greennode_vars:
        value = env_vars.get(var_name, "")
        secure_value = _secure_display_value(value) if value else "[red](missing)[/red]"
        status = "[green]✓[/green]" if value else "[red]✗[/red]"
        env_lines.append(f"{status} {var_name}: {secure_value}")

    env_panel = Panel(
        "\n".join(env_lines),
        title="[bold blue]GREENNODE Environment Variables[/bold blue]",
        border_style="blue",
    )
    console.print("\n")
    console.print(env_panel)

    # Prompt for missing values
    if missing_vars:
        console.print("\n[yellow]Some required environment variables are missing.[/yellow]")
        for var_name in missing_vars:
            value = Prompt.ask(
                f"Enter {var_name}",
                password=True,
                default="",
            )
            if value:
                env_vars[var_name] = value
                # Also set in environment for immediate use
                os.environ[var_name] = value
            else:
                logger.error(f"{var_name} is required but was not provided")
                console.print(f"[red]Error: {var_name} is required for deployment[/red]")
                raise click.Abort()

    # Save all env vars to runtime config
    # save_runtime_env_vars(env_vars)

    # All validations passed, proceed with deployment
    registry_url = get_config_value("GREENNODE_REGISTRY_URL")
    registry_username = get_config_value("GREENNODE_REGISTRY_USERNAME")
    registry_password = get_config_value("GREENNODE_REGISTRY_PASSWORD")

    # Determine image name
    custom_image = False
    if image_name is None:
        agent_identity = get_config_value("GREENNODE_AGENT_IDENTITY")
        if not agent_identity:
            logger.error("GREENNODE_AGENT_IDENTITY environment variable is required when image_name is not provided")
            console.print("[red]Error: GREENNODE_AGENT_IDENTITY environment variable is required[/red]")
            raise click.Abort()
        image_name = f"agentbase-worker-{agent_identity}"
        # logger.info("Using default image name: %s", image_name)
    else:
        custom_image = True
        # logger.info("Using custom image name: %s", image_name)

    # Generate tag (timestamp-based format: YYYYMMDD-HHMMSS)
    if not custom_image:
        tag = datetime.now().strftime("%Y%m%d-%H%M%S")
        full_image_name = f"{registry_url}/{image_name}:{tag}"
        # logger.info("Generated tag: %s", tag)
    else:
        full_image_name = image_name
    logger.info("Full image name: %s", full_image_name)

    # Create RuntimeClient early (needed for flavor details and later for runtime creation)
    iam_credentials = IAMCredentials(
        client_id=env_vars.get("GREENNODE_CLIENT_ID"),
        client_secret=env_vars.get("GREENNODE_CLIENT_SECRET"),
    )
    runtime_client = RuntimeClient(iam_credentials=iam_credentials)

    # Get or prompt for flavorId
    flavor_id = _get_or_prompt_flavor_id(runtime_client, console)

    # Get or prompt for autoscaling config
    autoscaling = _prompt_autoscaling(console)

    # Get all env vars from config file (includes all saved vars, not just required ones)
    all_env_vars = get_runtime_env_vars()

    # Display summary with secure values and get confirmation
    summary_lines = []

    # Add image name
    summary_lines.append(f"  Image Name: {full_image_name}")

    # Add flavor details if available
    if flavor_id:
        # Fetch flavor details to show name, CPU, RAM
        try:
            flavors_response = run_async_with_cleanup(runtime_client, runtime_client.list_all_async())
            flavors = flavors_response if isinstance(flavors_response, list) else (flavors_response.listData if hasattr(flavors_response, "listData") else [])
            selected_flavor = next((f for f in flavors if (f.get("id") if isinstance(f, dict) else getattr(f, "id", None)) == flavor_id), None)
            if selected_flavor:
                flavor_name = selected_flavor.get("name") if isinstance(selected_flavor, dict) else getattr(selected_flavor, "name", "Unknown")
                flavor_cpu = selected_flavor.get("cpu") if isinstance(selected_flavor, dict) else getattr(selected_flavor, "cpu", "N/A")
                flavor_ram = selected_flavor.get("ram") if isinstance(selected_flavor, dict) else getattr(selected_flavor, "ram", "N/A")
                summary_lines.append(f"  Flavor: {flavor_name} (CPU: {flavor_cpu}, RAM: {flavor_ram}MB)")
            else:
                summary_lines.append(f"  Flavor ID: {flavor_id}")
        except Exception:
            summary_lines.append(f"  Flavor ID: {flavor_id}")

    summary_lines.append(
        f"  Autoscaling: min={autoscaling.min_replicas}, max={autoscaling.max_replicas}, "
        f"cpu={autoscaling.cpu_utilization}%, memory={autoscaling.memory_utilization}%"
    )

    # Add all environment variables
    summary_lines.append("")  # Empty line separator
    summary_lines.append("  Environment Variables:")
    for var_name, value in sorted(all_env_vars.items()):
        secure_value = _secure_display_value(value) if value else "[red](empty)[/red]"
        summary_lines.append(f"    {var_name}: {secure_value}")

    summary_panel = Panel(
        "\n".join(summary_lines),
        title="[bold green]Runtime Configuration Summary[/bold green]",
        border_style="green",
    )
    console.print("\n")
    console.print(summary_panel)

    # Get user confirmation
    confirm = Prompt.ask("\nProceed with deployment?", default="Y", choices=["Y", "n", "N"])
    if confirm.upper() != "Y":
        logger.info("Deployment cancelled by user")
        console.print("[yellow]Deployment cancelled[/yellow]")
        return

    # Build and push Docker image (only if not using custom image)
    if not custom_image:
        _build_and_push_image(full_image_name, registry_username, registry_password)
    else:
        # Custom image provided, skip build and push
        logger.info("Skipping build and push for custom image: %s", full_image_name)
        console.print(f"\n[yellow]Using existing custom image: {full_image_name}[/yellow]")
        console.print("[dim]Skipping build and push steps...[/dim]")

    # Create runtime using Runtime API (always runs)
    runtime_client = RuntimeClient(iam_credentials=iam_credentials)
    try:
        console.print("\n[bold blue]Creating runtime...[/bold blue]")

        # Get all env vars from config (includes all saved vars)
        all_env_vars_for_request = get_runtime_env_vars()

        # Get command and args from config, default to empty arrays
        command = get_runtime_config_key("command", [])
        if not isinstance(command, list):
            command = []
        args = get_runtime_config_key("args", [])
        if not isinstance(args, list):
            args = []
        # Build runtime create request
        agent_identity = env_vars.get("GREENNODE_AGENT_IDENTITY")
        runtime_name = agent_identity or image_name

        # Build imageAuth if credentials provided
        image_auth = None
        if registry_username and registry_password:
            image_auth = AgentRuntimeImageAuth(
                enabled=True,
                username=registry_username,
                password=registry_password,
            )

        runtime_request = AgentRuntimeCreateRequest(
            name=runtime_name,
            description="",
            image_url=full_image_name,
            image_auth=image_auth,
            command=command,
            args=args,
            environment_variables=all_env_vars_for_request,
            flavor_id=flavor_id,
            autoscaling=autoscaling,
        )
        # Create runtime (using async method with run_async_with_cleanup)
        runtime_response = run_async_with_cleanup(runtime_client, runtime_client.create_async(request=runtime_request))

        # Handle response (could be dict or model)
        if hasattr(runtime_response, "id"):
            runtime_id = runtime_response.id
            runtime_name_resp = runtime_response.name
        else:
            runtime_id = runtime_response.get("id", "N/A") if isinstance(runtime_response, dict) else "N/A"
            runtime_name_resp = runtime_response.get("name", "N/A") if isinstance(runtime_response, dict) else "N/A"

        logger.info("Runtime created successfully: %s", runtime_id)
        if output == "id":
            console.print(runtime_id)
        else:
            # Display success message
            success_panel = Panel(
                f"[green]Runtime created successfully![/green]\n\n"
                f"Runtime ID: {runtime_id}\n"
                f"Runtime Name: {runtime_name_resp}\n"
                f"Image: {full_image_name}",
                title="[bold green]Runtime Deployment Complete[/bold green]",
                border_style="green",
            )
            console.print("\n")
            console.print(success_panel)
            console.print(f"[green]✓ Runtime created successfully with id: {runtime_id}[/green]")

    except Exception as runtime_error:
        # Log error and fail the deployment
        logger.error("Failed to create runtime: %s", runtime_error)
        console.print(f"\n[red]Error: Failed to create runtime: {runtime_error}[/red]")
        if not custom_image:
            console.print("[yellow]Image was built and pushed successfully, but runtime creation failed.[/yellow]")
        else:
            console.print("[yellow]Runtime creation failed.[/yellow]")
        console.print("[yellow]You can create the runtime manually using the Runtime API.[/yellow]")
        raise click.Abort()


@deploy_group.command(name="update")
@click.argument("runtime-id", required=True)
@click.option(
    "--image-name",
    "-i",
    type=str,
    default=None,
    help="Custom image name. If not provided, defaults to agentbase-worker-{agent_identity}",
)
@click.option(
    "--version",
    "-v",
    type=int,
    default=None,
    help="Runtime version to set on the default endpoint (if backend does not return it from patch).",
)
def deploy_update_command(runtime_id: str, image_name: Optional[str], version: Optional[int]) -> None:
    """Update an existing runtime with a new image (build, push, patch, switch default endpoint).

    Builds a Docker image, pushes it to the registry, patches the runtime with the new
    image URL, and switches the runtime's default endpoint to the newly built version.

    RUNTIME_ID: The ID of the existing runtime to update.

    Examples:
        \n
        # Update runtime with default image name\n
        greennode deploy update my-runtime-id

        \n
        # Update with custom image\n
        greennode deploy update my-runtime-id --image-name my-registry/my-agent:tag

        \n
        # Specify version if backend does not return it\n
        greennode deploy update my-runtime-id --version 2
    """
    console = Console()

    if get_config_value("GREENNODE_RUNTIME"):
        logger.info("Running in runtime environment, deployment bypassed")
        console.print("[yellow]Running in runtime environment, deployment bypassed[/yellow]")
        return

    logger.info("Starting deploy update for runtime %s...", runtime_id)
    console.print("[bold blue]Starting deploy update...[/bold blue]\n")

    all_required_met, status_dict = _check_and_display_deploy_config()
    if not all_required_met:
        missing_items = [key for key, value in status_dict.items() if not value]
        logger.warning("Missing required items: %s", ", ".join(missing_items))
        console.print(f"\n[red]Deployment aborted: Missing required items: {', '.join(missing_items)}[/red]")
        if "Docker" in missing_items:
            docker_cmd = "docker context inspect --format '{{ .Endpoints.docker.Host }}'"
            console.print(f"\n[red]⚠ Docker daemon is not running or engine mismatch.[/red]")
            console.print(f"[yellow]Check your socket with:[/yellow] [bold cyan]{docker_cmd}[/bold cyan]")
        raise click.Abort()

    ensure_runtime_config_exists()

    config_env_vars = get_runtime_env_vars()
    sensitive_vars = [
        "GREENNODE_CLIENT_ID",
        "GREENNODE_CLIENT_SECRET",
        "GREENNODE_AGENT_IDENTITY",
    ]
    found_sensitive_vars = [var for var in sensitive_vars if var in config_env_vars]
    if found_sensitive_vars:
        console.print(
            f"\n[red]Error: Sensitive environment variables in .greennode_runtime.json: "
            f"{', '.join(found_sensitive_vars)}[/red]"
        )
        raise click.Abort()

    required_greennode_vars = [
        "GREENNODE_CLIENT_ID",
        "GREENNODE_CLIENT_SECRET",
        "GREENNODE_AGENT_IDENTITY",
    ]
    env_vars = {}
    missing_vars = []
    for var_name in required_greennode_vars:
        value = get_config_value(var_name)
        if not value:
            missing_vars.append(var_name)
        else:
            env_vars[var_name] = value

    env_lines = []
    for var_name in required_greennode_vars:
        value = env_vars.get(var_name, "")
        secure_value = _secure_display_value(value) if value else "[red](missing)[/red]"
        status = "[green]✓[/green]" if value else "[red]✗[/red]"
        env_lines.append(f"{status} {var_name}: {secure_value}")
    console.print("\n")
    console.print(Panel("\n".join(env_lines), title="[bold blue]GREENNODE Environment Variables[/bold blue]", border_style="blue"))

    if missing_vars:
        console.print("\n[yellow]Some required environment variables are missing.[/yellow]")
        for var_name in missing_vars:
            value = Prompt.ask(f"Enter {var_name}", password=True, default="")
            if value:
                env_vars[var_name] = value
                os.environ[var_name] = value
            else:
                console.print(f"[red]Error: {var_name} is required[/red]")
                raise click.Abort()

    registry_url = get_config_value("GREENNODE_REGISTRY_URL")
    registry_username = get_config_value("GREENNODE_REGISTRY_USERNAME")
    registry_password = get_config_value("GREENNODE_REGISTRY_PASSWORD")

    custom_image = False
    if image_name is None:
        agent_identity = get_config_value("GREENNODE_AGENT_IDENTITY")
        if not agent_identity:
            console.print("[red]Error: GREENNODE_AGENT_IDENTITY is required when --image-name is not provided[/red]")
            raise click.Abort()
        image_name = f"agentbase-worker-{agent_identity}"
    else:
        custom_image = True

    if not custom_image:
        tag = datetime.now().strftime("%Y%m%d-%H%M%S")
        full_image_name = f"{registry_url}/{image_name}:{tag}"
    else:
        full_image_name = image_name
    logger.info("Full image name: %s", full_image_name)

    summary_lines = [
        f"  Runtime ID: {runtime_id}",
        f"  Image Name: {full_image_name}",
    ]
    console.print("\n")
    console.print(Panel("\n".join(summary_lines), title="[bold green]Update Summary[/bold green]", border_style="green"))
    confirm = Prompt.ask("\nProceed with update?", default="Y", choices=["Y", "n", "N"])
    if confirm.upper() != "Y":
        logger.info("Deploy update cancelled by user")
        console.print("[yellow]Update cancelled[/yellow]")
        return

    if not custom_image:
        _build_and_push_image(full_image_name, registry_username, registry_password)
    else:
        logger.info("Skipping build and push for custom image: %s", full_image_name)
        console.print(f"\n[yellow]Using existing custom image: {full_image_name}[/yellow]")
        console.print("[dim]Skipping build and push steps...[/dim]")

    iam_credentials = IAMCredentials(
        client_id=env_vars.get("GREENNODE_CLIENT_ID"),
        client_secret=env_vars.get("GREENNODE_CLIENT_SECRET"),
    )
    runtime_client = RuntimeClient(iam_credentials=iam_credentials)

    image_auth = None
    if registry_username and registry_password:
        image_auth = AgentRuntimeImageAuth(
            enabled=True,
            username=registry_username,
            password=registry_password,
        )

    try:
        current = run_async_with_cleanup(runtime_client, runtime_client.get_async(id=runtime_id))
    except Exception as e:
        err_msg = str(e).lower()
        if "404" in err_msg or "not found" in err_msg:
            console.print(f"\n[red]Error: Runtime {runtime_id} not found.[/red]")
        else:
            console.print(f"\n[red]Error: Failed to get runtime: {e}[/red]")
        logger.exception("Failed to get runtime")
        raise click.Abort()

    body = build_update_body_from_runtime(current)

    # Get current autoscaling for use as defaults when config is missing
    current_autoscaling = None
    a = body.get("autoscaling")
    if a is not None:
        if isinstance(a, AgentRuntimeAutoscaling):
            current_autoscaling = a
        elif isinstance(a, dict):
            try:
                current_autoscaling = AgentRuntimeAutoscaling(
                    min_replicas=a.get("minReplicas") or a.get("min_replicas", 1),
                    max_replicas=a.get("maxReplicas") or a.get("max_replicas", 1),
                    cpu_utilization=a.get("cpuUtilization") or a.get("cpu_utilization", 25),
                    memory_utilization=a.get("memoryUtilization") or a.get("memory_utilization", 25),
                )
            except Exception:
                pass
    autoscaling = _prompt_autoscaling(console, runtime_defaults=current_autoscaling)
    body["autoscaling"] = autoscaling

    # Ensure environment_variables is always a dict (required field)
    if not body.get("environment_variables"):
        config_env = get_runtime_env_vars()
        if config_env:
            body["environment_variables"] = config_env
        else:
            body["environment_variables"] = {}
    
    # Ensure command is always a list (required field)
    if "command" not in body or body["command"] is None:
        body["command"] = []
    
    # Ensure args is always a list (required field)
    if "args" not in body or body["args"] is None:
        body["args"] = []
    
    # Ensure flavor_id is set (required field) - check if missing or empty
    flavor_id_value = body.get("flavor_id")
    if not flavor_id_value or (isinstance(flavor_id_value, str) and not flavor_id_value.strip()):
        # Try to get from current runtime first (check both attribute and dict formats)
        flavor_from_current = None
        if hasattr(current, "flavor_id") and current.flavor_id:
            flavor_from_current = current.flavor_id
        elif hasattr(current, "flavorId") and current.flavorId:
            flavor_from_current = current.flavorId
        elif isinstance(current, dict):
            flavor_from_current = current.get("flavorId") or current.get("flavor_id")
        
        if flavor_from_current and (isinstance(flavor_from_current, str) and flavor_from_current.strip()):
            body["flavor_id"] = flavor_from_current
        else:
            # If not in current runtime, use helper function to get or prompt for flavor_id
            body["flavor_id"] = _get_or_prompt_flavor_id(runtime_client, console)
    
    # Ensure description is set (required field)
    if "description" not in body or body["description"] is None:
        # Try to get from current runtime
        if hasattr(current, "description") and current.description is not None:
            body["description"] = current.description
        elif isinstance(current, dict) and current.get("description") is not None:
            body["description"] = current.get("description")
        else:
            body["description"] = ""
    
    # Set image_url (required field)
    body["image_url"] = full_image_name
    
    # Set image_auth (optional field)
    body["image_auth"] = image_auth
    
    update_request = AgentRuntimeUpdateRequest(**body)

    try:
        console.print("\n[bold blue]Patching runtime...[/bold blue]")
        patch_result = run_async_with_cleanup(runtime_client, runtime_client.update_async(id=runtime_id, request=update_request))
    except Exception as e:
        err_msg = str(e).lower()
        if "404" in err_msg or "not found" in err_msg:
            console.print(f"\n[red]Error: Runtime {runtime_id} not found.[/red]")
        else:
            console.print(f"\n[red]Error: Failed to patch runtime: {e}[/red]")
        logger.exception("Failed to patch runtime")
        raise click.Abort()

    new_version = None
    if hasattr(patch_result, "version") and patch_result.version is not None:
        new_version = patch_result.version
    elif isinstance(patch_result, dict) and patch_result.get("version") is not None:
        new_version = patch_result["version"]
    if new_version is None and hasattr(runtime_client, "list_versions_async"):
        try:
            versions_response = run_async_with_cleanup(runtime_client, runtime_client.list_versions_async(id=runtime_id))
            versions = []
            if hasattr(versions_response, "listData") and versions_response.listData:
                versions = versions_response.listData
            elif isinstance(versions_response, list):
                versions = versions_response
            if versions:
                by_ver = sorted(
                    versions,
                    key=lambda v: (v.version if hasattr(v, "version") else v.get("version")) or 0,
                    reverse=True,
                )
                top = by_ver[0]
                new_version = top.version if hasattr(top, "version") else top.get("version")
        except Exception:
            pass
    if new_version is None and version is not None:
        new_version = version
    if new_version is None:
        console.print("[yellow]Runtime patched; could not determine new version. Skipping default endpoint update.[/yellow]")
        console.print(f"[green]✓ Runtime {runtime_id} updated with image {full_image_name}[/green]")
        return

    try:
        endpoints_response = run_async_with_cleanup(runtime_client, runtime_client.list_endpoints_async(id=runtime_id, page=0, size=100))
    except Exception as e:
        console.print(f"[yellow]Warning: Could not list endpoints: {e}. Runtime was updated.[/yellow]")
        console.print(f"[green]✓ Runtime {runtime_id} updated with image {full_image_name}[/green]")
        return

    endpoints = []
    if hasattr(endpoints_response, "listData") and endpoints_response.listData:
        endpoints = list(endpoints_response.listData)
    elif isinstance(endpoints_response, list):
        endpoints = endpoints_response

    default_endpoint = None
    for ep in endpoints:
        name = ep.name if hasattr(ep, "name") else (ep.get("name") if isinstance(ep, dict) else None)
        if name == "default":
            default_endpoint = ep
            break
    if default_endpoint is None and endpoints:
        default_endpoint = endpoints[0]

    if default_endpoint is None:
        console.print("[yellow]Runtime has no endpoints; default endpoint was not updated.[/yellow]")
        console.print(f"[green]✓ Runtime {runtime_id} updated with image {full_image_name}[/green]")
        return

    endpoint_id = default_endpoint.id if hasattr(default_endpoint, "id") else default_endpoint.get("id")
    if not endpoint_id:
        console.print(f"[green]✓ Runtime {runtime_id} updated with image {full_image_name}[/green]")
        return

    try:
        run_async_with_cleanup(
            runtime_client,
            runtime_client.update_endpoint_async(
                id=runtime_id,
                endpointId=endpoint_id,
                version=new_version,
            )
        )
        console.print(f"[green]✓ Runtime {runtime_id} updated; default endpoint set to version {new_version}[/green]")
    except Exception as e:
        console.print(f"[yellow]Warning: Could not update default endpoint to version {new_version}: {e}[/yellow]")
        console.print(f"[green]✓ Runtime {runtime_id} updated with image {full_image_name}[/green]")
